538		{
539			if (extract_begin_struct(extract, fz_struct_to_extract(standard), idx, -1))
540				fz_throw(ctx, FZ_ERROR_LIBRARY, "Failed to begin struct");
541		}
542		fz_always(ctx)
543			dev->writer->ctx = NULL;
544		fz_catch(ctx)
