752	/* Will drop <out> if an error occurs. */
753	static fz_document_writer *fz_new_docx_writer_internal(fz_context *ctx, fz_output *out,
754			const char *options_string, extract_format_t format)
755	{
756		fz_docx_writer *writer = NULL;
757		fz_options *options = NULL;
758		double space_guess = 0;
759	
760		fz_var(writer);
761		fz_var(options);
762	
763		fz_try(ctx)
764		{
765			options = fz_new_options(ctx, options_string);
766			space_guess = get_double_option(ctx, options, "space-guess", 0);
767			writer = fz_new_derived_document_writer(
768					ctx,
769					fz_docx_writer,
770					writer_begin_page,
771					writer_end_page,
772					writer_close,
773					writer_drop
774					);
775			writer->ctx = ctx;
776			writer->output = out;
777			if (get_bool_option(ctx, options, "html", 0)) format = extract_format_HTML;
778			if (get_bool_option(ctx, options, "text", 0)) format = extract_format_TEXT;
779			if (get_bool_option(ctx, options, "json", 0)) format = extract_format_JSON;
780			if (extract_alloc_create(s_realloc_fn, writer, &writer->alloc))
781				fz_throw(ctx, FZ_ERROR_LIBRARY, "Failed to create extract_alloc instance");
782			if (extract_begin(writer->alloc, format, &writer->extract))
783				fz_throw(ctx, FZ_ERROR_LIBRARY, "Failed to create extract instance");
784			if (space_guess)
785				extract_set_space_guess(writer->extract, space_guess);
786			writer->spacing = get_bool_option(ctx, options, "spacing", 0);
787			writer->rotation = get_bool_option(ctx, options, "rotation", 1);
788			writer->images = get_bool_option(ctx, options, "images", 1);
789			writer->mediabox_clip = get_bool_option(ctx, options, "mediabox-clip", 1);
790			if (extract_set_layout_analysis(writer->extract, get_bool_option(ctx, options, "analyse", 0)))
791				fz_throw(ctx, FZ_ERROR_LIBRARY, "extract_enable_analysis failed.");
792			{
793				const char* v;
794				if (fz_lookup_option(ctx, options, "tables-csv-format", &v))
795				{
796					fprintf(stderr, "tables-csv-format: %s\n", v);
797					if (extract_tables_csv_format(writer->extract, v))
798					{
799						fz_throw(ctx, FZ_ERROR_LIBRARY, "extract_tables_csv_format() failed.");
800					}
801				}
802			}
803			writer->ctx = NULL;
804			fz_validate_options(ctx, options, "docx");
805		}
806		fz_catch(ctx)
807		{
808			fz_drop_options(ctx, options);
809			/* fz_drop_document_writer() drops its output so we only need to call
810			fz_drop_output() if we failed before creating the writer. */
811			if (writer)
812			{
813				writer->ctx = ctx;
814				fz_drop_document_writer(ctx, &writer->super);
815				writer->ctx = NULL;
816			}
817			else
818				fz_drop_output(ctx, out);
819			fz_rethrow(ctx);
820		}
821		return &writer->super;
822	}
