130	static int is_extension(const char *a, const char *ext)
131	{
132		if (!a)
133			return 0;
134		if (a[0] == '.')
135			++a;
136		return !fz_strcasecmp(a, ext);
137	}
138	
139	static const char *prev_period(const char *start, const char *p)
140	{
141		while (--p > start)
142			if (*p == '.')
143				return p;
144		return NULL;
145	}
