148	fz_new_document_writer(fz_context *ctx, const char *path, const char *explicit_format, const char *options)
149	{
150		const char *format = explicit_format;
151		if (!format)
152			format = strrchr(path, '.');
153		while (format)
154		{
155	#if FZ_ENABLE_OCR_OUTPUT
156			if (is_extension(format, "ocr"))
157				return fz_new_pdfocr_writer(ctx, path, options);
158	#endif
159	#if FZ_ENABLE_PDF
160			if (is_extension(format, "pdf"))
161				return fz_new_pdf_writer(ctx, path, options);
162	#endif
163	
164			if (is_extension(format, "cbz"))
165				return fz_new_cbz_writer(ctx, path, options);
166			if (is_extension(format, "csv"))
167				return fz_new_csv_writer(ctx, path, options);
168	
169			if (is_extension(format, "svg"))
170				return fz_new_svg_writer(ctx, path, options);
171	
172			if (is_extension(format, "png"))
173				return fz_new_png_pixmap_writer(ctx, path, options);
174			if (is_extension(format, "pam"))
175				return fz_new_pam_pixmap_writer(ctx, path, options);
176			if (is_extension(format, "pnm"))
177				return fz_new_pnm_pixmap_writer(ctx, path, options);
178			if (is_extension(format, "pgm"))
179				return fz_new_pgm_pixmap_writer(ctx, path, options);
180			if (is_extension(format, "ppm"))
181				return fz_new_ppm_pixmap_writer(ctx, path, options);
182			if (is_extension(format, "pbm"))
183				return fz_new_pbm_pixmap_writer(ctx, path, options);
184			if (is_extension(format, "pkm"))
185				return fz_new_pkm_pixmap_writer(ctx, path, options);
186			if (is_extension(format, "jpeg") || is_extension(format, "jpg"))
187				return fz_new_jpeg_pixmap_writer(ctx, path, options);
188	
189			if (is_extension(format, "pcl"))
190				return fz_new_pcl_writer(ctx, path, options);
191			if (is_extension(format, "pclm"))
192				return fz_new_pclm_writer(ctx, path, options);
193			if (is_extension(format, "ps"))
194				return fz_new_ps_writer(ctx, path, options);
195			if (is_extension(format, "pwg"))
196				return fz_new_pwg_writer(ctx, path, options);
197	
198			if (is_extension(format, "txt") || is_extension(format, "text"))
199				return fz_new_text_writer(ctx, "text", path, options);
200			if (is_extension(format, "html"))
201				return fz_new_text_writer(ctx, "html", path, options);
202			if (is_extension(format, "xhtml"))
203				return fz_new_text_writer(ctx, "xhtml", path, options);
204			if (is_extension(format, "stext") || is_extension(format, "stext.xml"))
205				return fz_new_text_writer(ctx, "stext.xml", path, options);
206			if (is_extension(format, "stext.json"))
207				return fz_new_text_writer(ctx, "stext.json", path, options);
208	
209	#if FZ_ENABLE_ODT_OUTPUT
210			if (is_extension(format, "odt"))
211				return fz_new_odt_writer(ctx, path, options);
212	#endif
213	#if FZ_ENABLE_DOCX_OUTPUT
214			if (is_extension(format, "docx"))
215				return fz_new_docx_writer(ctx, path, options);
216	#endif
217			if (format != explicit_format)
218				format = prev_period(path, format);
219			else
220				format = NULL;
221		}
222		fz_throw(ctx, FZ_ERROR_ARGUMENT, "cannot detect document format");
223	}
